function usePartyRoomMembers(roomId: string) {
  const [members, setMembers] = useState<Member[]>([]);

  useEffect(() => {
    // BUG: dependency [] — closure giữ roomId tại lần mount đầu tiên mãi mãi
    return subscribeRealtime(RealtimeEvents.PartyMemberJoined, (data) => {
      if (data.roomId === roomId) setMembers((m) => [...m, data.member]);
    });
  }, []);

  return members;
}
